import os
import sys
import boto3


def list_s3_files(bucket_name):
    """List all files in an S3 bucket using credentials from environment variables."""

    # Retrieve credentials from environment variables
    aws_access_key_id = os.environ.get("AWS_ACCESS_KEY_ID")
    aws_secret_access_key = os.environ.get("AWS_SECRET_ACCESS_KEY")
    aws_region = os.environ.get("AWS_DEFAULT_REGION", "us-east-1")

    if not aws_access_key_id or not aws_secret_access_key:
        print("ERROR: AWS credentials not found in environment variables.")
        print()
        print("Please set the following environment variables before running this script:")
        print()
        print("  On Linux/macOS:")
        print("    export AWS_ACCESS_KEY_ID='your-access-key-id'")
        print("    export AWS_SECRET_ACCESS_KEY='your-secret-access-key'")
        print("    export AWS_DEFAULT_REGION='us-east-1'  # optional")
        print()
        print("  On Windows (Command Prompt):")
        print("    set AWS_ACCESS_KEY_ID=your-access-key-id")
        print("    set AWS_SECRET_ACCESS_KEY=your-secret-access-key")
        print("    set AWS_DEFAULT_REGION=us-east-1")
        print()
        print("  On Windows (PowerShell):")
        print('    $env:AWS_ACCESS_KEY_ID="your-access-key-id"')
        print('    $env:AWS_SECRET_ACCESS_KEY="your-secret-access-key"')
        print('    $env:AWS_DEFAULT_REGION="us-east-1"')
        print()
        print("Alternatively, place a .env file in the same directory as this script")
        print("with the following contents:")
        print()
        print("  AWS_ACCESS_KEY_ID=your-access-key-id")
        print("  AWS_SECRET_ACCESS_KEY=your-secret-access-key")
        print("  AWS_DEFAULT_REGION=us-east-1")
        sys.exit(1)

    # Create S3 client with credentials from environment
    s3_client = boto3.client(
        "s3",
        aws_access_key_id=aws_access_key_id,
        aws_secret_access_key=aws_secret_access_key,
        region_name=aws_region,
    )

    print(f"Listing files in bucket: {bucket_name}")
    print("-" * 60)

    try:
        paginator = s3_client.get_paginator("list_objects_v2")
        file_count = 0

        for page in paginator.paginate(Bucket=bucket_name):
            if "Contents" not in page:
                continue
            for obj in page["Contents"]:
                file_count += 1
                size_kb = obj["Size"] / 1024
                last_modified = obj["LastModified"].strftime("%Y-%m-%d %H:%M:%S")
                print(f"  {obj['Key']:<50} {size_kb:>10.1f} KB  {last_modified}")

        print("-" * 60)
        print(f"Total files: {file_count}")

    except s3_client.exceptions.NoSuchBucket:
        print(f"ERROR: Bucket '{bucket_name}' does not exist.")
        sys.exit(1)
    except Exception as e:
        print(f"ERROR: {e}")
        sys.exit(1)


def _load_dotenv_if_available():
    """Load environment variables from a .env file if it exists."""
    dotenv_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".env")
    if os.path.exists(dotenv_path):
        print(f"Loading credentials from {dotenv_path}")
        with open(dotenv_path, "r") as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                if "=" in line:
                    key, _, value = line.partition("=")
                    key = key.strip()
                    value = value.strip().strip("'\"")
                    if key and value:
                        os.environ.setdefault(key, value)


if __name__ == "__main__":
    # Attempt to load .env file for convenience during demos
    _load_dotenv_if_available()

    BUCKET_NAME = "demo-bucket"
    list_s3_files(BUCKET_NAME)